class Solution {
public:
    int clumsy(int n) {
        if (n <= 2) return n;
        int result = n;
        n -= 1;
        int ops[] = { '*', '/', '+', '-' };
        int opIndex = 0;
        while (n > 0) {
            result = ops[opIndex % 4] == '*' ? result * n : ops[opIndex % 4] == '/' ? result / n : ops[opIndex % 4] == '+' ? result + n : result - n;
            opIndex++;
            n -= 1;
        }
        return result;
    }
};
```
